using Microsoft.AspNetCore.Mvc;
using System.IO;
namespace FileUploaderApp.Controllers
{    
    [Route("api/[controller]")] // Route Template 
    public class FilesController : ControllerBase   {        
        private const string uploadsFolder = "uploads";      
         
        /// <summary>     
        /// Serves the file from a specific route parameter. Returns it with appropriate content type    
        /// Example: GET api/files/{filename}   
        /// </summary> 
         [HttpGet("{fileName}")]  // Route Template Parameter  
          public IActionResult GetFile(string fileName)      {            
              var path = Path.Combine(Directory.GetCurrentDirectory(), uploadsFolder, fileName);    
               if (!System.IO.File.Exists(path))       return NotFound();         // File not found 
               
            string extension=Path.GetExtension(fileName).Replace(".","");   
              switch (extension)      {        case "doc" or "docs":return File(path, "application/vnd.ms-word", filename);          default: return File(path, $"application/{extension}",filename );             }         // Return appropriate content type and file name     }}